        /// <returns>An instance of a mutable document initialized with the given property values.</returns>
        public static JsonDocumentBuilder<Mutable> CreateBuilder(JsonWorkspace workspace, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.AutoCleanClosureEntity.Source autoCleanClosure = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.FailSpecWithNoExpectationsEntity.Source failSpecWithNoExpectations = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.HideDisbaledEntity.Source hideDisbaled = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.WhetherToRandomizeSpecExecutionOrder.Source random = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.SeedEntity.Source seed = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.StopOnSpecFailureEntity.Source stopOnSpecFailure = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.WhetherToCauseSpecsToOnlyHaveOneExpectationFailure.Source stopSpecOnExpectationFailure = default, in Corvus.JasmineBenchmark.Current.JasmineSchema.EnvItems.VerboseDepricationEntity.Source verboseDeprication = default, int initialCapacity = 30)
        {
