            ComplexValueBuilder cvb = ComplexValueBuilder.Create(documentBuilder, initialCapacity);
            cvb.StartObject();
            Builder ovb = new(cvb);
            ovb.Create(autoCleanClosure, failSpecWithNoExpectations, hideDisbaled, random, seed, stopOnSpecFailure, stopSpecOnExpectationFailure, verboseDeprication);
            cvb = ovb._builder;
            cvb.EndObject();
            ((IMutableJsonDocument)documentBuilder).SetAndDispose(ref cvb);
